diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..75e04a665c25 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2719,6 +2719,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   // Note: We don't generate the inverse max/min, just create the 'not' of
   // it and let other folds do the rest.
   if (match(Op0, m_Not(m_Value(X))) &&
+
       match(Op1, m_c_MaxOrMin(m_Specific(Op0), m_Value(Y))) &&
       !Op0->hasNUsesOrMore(3) && isFreeToInvert(Y, Y->hasOneUse())) {
     Value *Not = Builder.CreateNot(Op1);
@@ -2869,6 +2870,62 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     }
   }

+  // min/max(X + 1, Y) - min/max(X, Y) patterns
+  // These produce 0 or 1 depending on the relationship between X and Y.
+  {
+    Value *Add;
+    const APInt *C;
+    // smin(X + 1, Y) - smin(X, Y) => X < Y ? 1 : 0
+    // Requires nsw on the add to avoid signed overflow issues.
+    if (match(Op0, m_OneUse(m_c_SMin(m_Value(Add), m_Value(Y)))) &&
+        match(Add, m_c_Add(m_Value(X), m_APInt(C))) &&
+        isa<OverflowingBinaryOperator>(Add) &&
+        cast<OverflowingBinaryOperator>(Add)->hasNoSignedWrap() &&
+        C->isOne() &&
+        match(Op1, m_OneUse(m_c_SMin(m_Specific(X), m_Specific(Y))))) {
+      Value *Cmp = Builder.CreateICmpSLT(X, Y);
+      return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                ConstantInt::get(Ty, 0));
+    }
+
+    // smax(X + 1, Y) - smax(X, Y) => X >= Y ? 1 : 0
+    if (match(Op0, m_OneUse(m_c_SMax(m_Value(Add), m_Value(Y)))) &&
+        match(Add, m_c_Add(m_Value(X), m_APInt(C))) &&
+        isa<OverflowingBinaryOperator>(Add) &&
+        cast<OverflowingBinaryOperator>(Add)->hasNoSignedWrap() &&
+        C->isOne() &&
+        match(Op1, m_OneUse(m_c_SMax(m_Specific(X), m_Specific(Y))))) {
+      Value *Cmp = Builder.CreateICmpSGE(X, Y);
+      return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                ConstantInt::get(Ty, 0));
+    }
+
+    // umin(X + 1, Y) - umin(X, Y) => X <u Y ? 1 : 0
+    // Requires nuw on the add to avoid unsigned overflow issues.
+    if (match(Op0, m_OneUse(m_c_UMin(m_Value(Add), m_Value(Y)))) &&
+        match(Add, m_c_Add(m_Value(X), m_APInt(C))) &&
+        isa<OverflowingBinaryOperator>(Add) &&
+        cast<OverflowingBinaryOperator>(Add)->hasNoUnsignedWrap() &&
+        C->isOne() &&
+        match(Op1, m_OneUse(m_c_UMin(m_Specific(X), m_Specific(Y))))) {
+      Value *Cmp = Builder.CreateICmpULT(X, Y);
+      return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                ConstantInt::get(Ty, 0));
+    }
+
+    // umax(X + 1, Y) - umax(X, Y) => X >=u Y ? 1 : 0
+    if (match(Op0, m_OneUse(m_c_UMax(m_Value(Add), m_Value(Y)))) &&
+        match(Add, m_c_Add(m_Value(X), m_APInt(C))) &&
+        isa<OverflowingBinaryOperator>(Add) &&
+        cast<OverflowingBinaryOperator>(Add)->hasNoUnsignedWrap() &&
+        C->isOne() &&
+        match(Op1, m_OneUse(m_c_UMax(m_Specific(X), m_Specific(Y))))) {
+      Value *Cmp = Builder.CreateICmpUGE(X, Y);
+      return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                ConstantInt::get(Ty, 0));
+    }
+  }
+
   if (Instruction *Res = foldBinOpOfSelectAndCastOfSelectCondition(I))
     return Res;

@@ -2920,6 +2977,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   return TryToNarrowDeduceFlags();
 }

+
 /// This eliminates floating-point negation in either 'fneg(X)' or
 /// 'fsub(-0.0, X)' form by combining into a constant operand.
 static Instruction *foldFNegIntoConstant(Instruction &I, const DataLayout &DL) {

